    original_sql: `SELECT COUNT(DISTINCT G.lead_key) AS cnt\nFROM ktws.FCT_LEAD AS G\n       INNER JOIN ktws.DIM_MNG_USER AS D ON G.cl_sc_key = D.sc_key\n       INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key\n       INNER JOIN ktws.DIM_CALENDAR_KTWS AS H ON G.lead_reg_dt = H.Date\nWHERE H.YearMonth = '2026-04'\n  AND G.lead_key IN (\n      SELECT ACT.lead_key\n      FROM ktws.FCT_ACTIVITY_v2 AS ACT\n               INNER JOIN ktws.DIM_CRM_ACT_TYPE AS ACT_B ON ACT.tp_key = ACT_B.tp_key\n               INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS ACT_F ON ACT_B.common_tp_nm = ACT_F.common_tp_nm\n      WHERE ACT_B.tp_grp_1 IN ('관계형성', '기회창출')\n        AND ACT.act_result <> '부재중'\n  )\n  AND (G.close_dt > EOMONTH('2026-04-01') OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)\n  AND D.facade_sc_yn != '창구SC'\n  AND D.name NOT IN ('고객지원팀', 'TOYOTA YM')\n  AND D.user_id NOT IN ('DM5103', 'DM9999', 'JB30016', 'KMKS176', 'KMKS999', 'JB30067')\n  AND D.active_yn = '재직'\n  AND E.dealer_nm = '렉서스 강남'`,
