    original_sql: `WITH qualified_lead AS (\n    SELECT lead_key, cl_sc_key, tp_key\n    FROM ktws.FCT_LEAD AS l\n    WHERE ( l.close_dt > '2026-04-30' OR l.close_dt IS NULL OR l.last_retail_sales_dt IS NOT NULL )\n        AND EXISTS (\n            SELECT 1 FROM ktws.FCT_ACTIVITY_v2 AS a\n                INNER JOIN ktws.DIM_CRM_ACT_TYPE AS at2 ON a.tp_key = at2.tp_key\n            WHERE a.lead_key = l.lead_key AND at2.tp_grp_1 IN ('관계형성', '기회창출')\n              AND a.act_result <> '부재중' AND a.lead_key IS NOT NULL\n        )\n),\nlead AS (\n    SELECT COUNT(DISTINCT l.lead_key) AS lead_cnt\n    FROM ktws.FCT_LEAD AS l\n        INNER JOIN ktws.DIM_CALENDAR_KTWS AS c ON l.lead_reg_dt = c.[Date]\n        INNER JOIN ktws.DIM_MNG_USER AS u ON l.cl_sc_key = u.sc_key\n        INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\n    WHERE c.[Year] = 2026 AND c.[MonthNumber] = 4\n        AND ( l.close_dt > '2026-04-30' OR l.close_dt IS NULL OR l.last_retail_sales_dt IS NOT NULL )\n        AND EXISTS (SELECT 1 FROM ktws.FCT_ACTIVITY_v2 AS a INNER JOIN ktws.DIM_CRM_ACT_TYPE AS at2 ON a.tp_key = at2.tp_key\n                     WHERE a.lead_key = l.lead_key AND at2.tp_grp_1 IN ('관계형성', '기회창출') AND a.act_result <> '부재중')\n        AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n        AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\n        AND d.dealer_nm = '렉서스 강남'\n),\ncntrct AS (\n    SELECT SUM(f.cnt) AS cntrct_cnt\n    FROM ktws.FCT_CONTRACT_KTWS AS f\n        INNER JOIN ktws.DIM_CALENDAR_KTWS AS c ON f.contract_dt = c.[Date]\n        INNER JOIN ktws.DIM_MNG_USER AS u ON f.cn_sc_key = u.sc_key\n        INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\n        INNER JOIN (SELECT DISTINCT lead_key FROM qualified_lead) AS ql ON f.lead_key = ql.lead_key\n    WHERE c.[Year] = 2026 AND c.[MonthNumber] = 4\n        AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n        AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\n        AND d.dealer_nm = '렉서스 강남'\n)\nSELECT FORMAT(CAST(ISNULL(C.cntrct_cnt,0) AS DECIMAL(18,4)) / NULLIF(L.lead_cnt, 0), '0%') AS Percentage\nFROM cntrct AS C CROSS JOIN lead AS L`,
