    source_sql_id: 'src_fs32', source_document: '1-1시트 시승건수(당월활동실적/시승완료)', dialect: 'tsql',
    original_sql: `WITH mtd_dates AS (\n    SELECT [Date] FROM ktws.DIM_CALENDAR_KTWS WHERE [Date] >= '2026-04-01' AND [Date] <= '2026-04-30'\n),\nfiltered_users AS (\n    SELECT D.sc_key FROM ktws.DIM_MNG_USER AS D\n    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key\n    WHERE D.facade_sc_yn <> '창구SC' AND D.name NOT IN ('고객지원팀', 'TOYOTA YM')\n      AND D.user_id NOT IN ('DM5103', 'DM9999', 'JB30016', 'KMKS176', 'KMKS999', 'JB30067')\n      AND D.active_yn = '재직' AND E.dealer_nm = '렉서스 강남'\n      AND D.BRAND = 'LEXUS' AND D.group_name = '렉서스 강서' AND D.dept_nm = '강서영업팀'\n),\nact_grp AS (\n    SELECT DISTINCT ACT.lead_key FROM ktws.FCT_ACTIVITY_v2 AS ACT\n    INNER JOIN mtd_dates AS DT ON ACT.act_dt_fr = DT.[Date]\n    INNER JOIN filtered_users AS U ON ACT.sc_key = U.sc_key\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS ACT_B ON ACT.tp_key = ACT_B.tp_key\n    WHERE ACT_B.tp_grp_1 IN ('관계형성', '기회창출')\n      AND (ACT.act_result <> '부재중' OR ACT.act_result IS NULL)\n      AND (ACT.contact_tp <> 'MSG' OR ACT.contact_tp IS NULL) AND ACT.lead_key IS NOT NULL\n),\nlead_grp AS (\n    SELECT DISTINCT G.lead_key FROM ktws.FCT_LEAD AS G\n    INNER JOIN mtd_dates AS DT ON G.lead_reg_dt = DT.[Date]\n    INNER JOIN filtered_users AS U ON G.cl_sc_key = U.sc_key\n    INNER JOIN act_grp AS A ON G.lead_key = A.lead_key\n    WHERE G.close_dt > EOMONTH('2026-04-30') OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL\n),\nfinal_activity AS (\n    SELECT COUNT(DISTINCT ACT.lead_key) AS cnt FROM ktws.FCT_ACTIVITY_v2 AS ACT\n    INNER JOIN mtd_dates AS DT ON ACT.act_dt_fr = DT.[Date]\n    INNER JOIN filtered_users AS U ON ACT.sc_key = U.sc_key\n    INNER JOIN lead_grp AS L ON ACT.lead_key = L.lead_key\n    WHERE ACT.act_tp = 'P113' AND ACT.act_result = '시승완료' AND ACT.lead_key IS NOT NULL\n)\nSELECT COALESCE(cnt, 0) AS cnt FROM final_activity`,
