    source_sql_id: 'src_fs40', source_document: '1-2시트 계약 진행률(조직별 목록)', dialect: 'tsql',
    original_sql: `WITH elig_user AS (\n    SELECT u.sc_key, dlr.dealer_nm, u.group_name, u.dept_nm, u.[name]\n    FROM ktws.DIM_MNG_USER AS u\n    LEFT JOIN ktws.DIM_MNG_DEALER AS dlr ON u.dealer_key = dlr.dealer_key\n    WHERE ISNULL(u.facade_sc_yn, '') <> '창구SC'\n      AND u.[name] NOT IN ('고객지원팀', 'TOYOTA YM')\n      AND u.user_id NOT IN ('DM5103','DM9999','JB30007','JB30016','KMKS176','KMKS999','JB30067')\n),\ncntrct_funnel AS (\n    SELECT eu.dealer_nm, eu.group_name, eu.dept_nm, eu.[name],\n        SUM(c.cnt) AS cntrct_cnt\n    FROM ktws.FCT_CONTRACT_KTWS AS c\n    JOIN elig_user AS eu ON c.cn_sc_key = eu.sc_key\n    JOIN ktws.DIM_CRM_ACT_TYPE AS ct ON c.tp_key = ct.tp_key\n    WHERE c.contract_dt >= '2026-04-01' AND c.contract_dt <= '2026-04-30'\n      AND EXISTS (\n            SELECT 1 FROM ktws.FCT_LEAD AS l\n            JOIN ktws.DIM_CRM_ACT_TYPE AS lct ON l.tp_key = lct.tp_key\n            WHERE l.lead_key = c.lead_key AND l.cl_sc_key = c.cn_sc_key\n              AND lct.common_tp_nm = ct.common_tp_nm\n              AND l.lead_reg_dt >= '2026-04-01' AND l.lead_reg_dt <= '2026-04-30'\n              AND ( l.close_dt > '2026-04-30' OR l.close_dt IS NULL OR l.last_retail_sales_dt IS NOT NULL )\n              AND EXISTS (\n                    SELECT 1 FROM ktws.FCT_ACTIVITY_v2 AS a\n                    JOIN ktws.DIM_CRM_ACT_TYPE AS act ON a.tp_key = act.tp_key\n                    WHERE a.lead_key = l.lead_key AND a.sc_key = c.cn_sc_key\n                      AND act.common_tp_nm = ct.common_tp_nm AND act.tp_grp_1 IN ('관계형성', '기회창출')\n                      AND ( a.act_result IS NULL OR a.act_result <> '부재중' ) AND a.lead_key IS NOT NULL\n                      AND a.act_dt_fr >= '2026-04-01' AND a.act_dt_fr <= '2026-04-30'\n              )\n      )\n    GROUP BY eu.dealer_nm, eu.group_name, eu.dept_nm, eu.[name]\n),\ntgt AS (\n    SELECT eu.dealer_nm, eu.group_name, eu.dept_nm, eu.[name],\n        SUM(t.target_cnt) AS target_cnt\n    FROM ktws.FCT_CRM_TARGET_M AS t\n    JOIN elig_user AS eu ON t.sc_key = eu.sc_key\n    JOIN ktws.DIM_CRM_ACT_TYPE AS tct ON t.tp_key = tct.tp_key\n    WHERE t.monthly_dt >= '2026-04-01' AND t.monthly_dt <= '2026-04-30'\n      AND tct.common_tp_nm = '계약'\n    GROUP BY eu.dealer_nm, eu.group_name, eu.dept_nm, eu.[name]\n)\nSELECT\n    COALESCE(cf.dealer_nm, t.dealer_nm) AS dealer_nm,\n    COALESCE(cf.group_name, t.group_name) AS group_name,\n    COALESCE(cf.dept_nm, t.dept_nm) AS dept_nm,\n    COALESCE(cf.[name], t.[name]) AS [name],\n    CASE WHEN ISNULL(t.target_cnt, 0) = 0 THEN 1.0\n         ELSE CAST(ISNULL(cf.cntrct_cnt, 0) AS float) / t.target_cnt\n    END AS progress_cntrct_funnel_mtd_sc_cond\nFROM tgt AS t\nFULL OUTER JOIN cntrct_funnel AS cf\n    ON t.dealer_nm = cf.dealer_nm AND t.group_name = cf.group_name\n    AND t.dept_nm = cf.dept_nm AND t.[name] = cf.[name]\nORDER BY dealer_nm, group_name, dept_nm, [name]`,
