    original_sql: `SELECT\n    CASE WHEN SUM(CASE WHEN c.kr_holiday = '0' THEN 1 ELSE 0 END) = 0 THEN 0.0\n         ELSE CAST(SUM(CASE WHEN c.[Date] <= CAST(GETDATE() AS DATE) AND c.kr_holiday = '0'\n                            THEN 1 ELSE 0 END) AS float)\n              / SUM(CASE WHEN c.kr_holiday = '0' THEN 1 ELSE 0 END)\n    END AS progress_working_day\nFROM ktws.DIM_CALENDAR_KTWS AS c\nWHERE c.[Year] = 2026 AND c.[MonthNumber] = 4`,
