    original_sql: `WITH act_actual AS (\n    SELECT SUM(f.actual_cnt) AS ac_cnt FROM ktws.FCT_ACTIVITY_v2 AS f\n        INNER JOIN ktws.DIM_CALENDAR_KTWS AS c ON f.act_dt_fr = c.[Date]\n        INNER JOIN ktws.DIM_CRM_ACT_TYPE AS t ON f.tp_key = t.tp_key\n        INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS aord ON t.common_tp_nm = aord.common_tp_nm\n        INNER JOIN ktws.DIM_MNG_USER AS u ON f.sc_key = u.sc_key\n        INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\n    WHERE t.tp_grp_1 IN ('관계형성', '기회창출') AND c.[Year] = 2026 AND c.[MonthNumber] = 4\n        AND d.dealer_nm IS NOT NULL AND LTRIM(RTRIM(d.dealer_nm)) <> ''\n        AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n        AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\n        AND u.user_id NOT IN ('DM5103','DM9999','JB30007','JB30016','KMKS176','KMKS999','JB30067')\n),\nact_target AS (\n    SELECT SUM(f.target_cnt) AS tgt_cnt FROM ktws.FCT_CRM_TARGET_D AS f\n        INNER JOIN ktws.DIM_CALENDAR_KTWS AS c ON f.daily_dt = c.[Date]\n        INNER JOIN ktws.DIM_CRM_ACT_TYPE AS t ON f.type_cd = t.tp_key\n        INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS aord ON t.common_tp_nm = aord.common_tp_nm\n        INNER JOIN ktws.DIM_MNG_USER AS u ON f.sc_key = u.sc_key\n        INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\n    WHERE aord.tp_grp_1 IN ('관계형성', '기회창출') AND c.[Year] = 2026 AND c.[MonthNumber] = 4\n        AND d.dealer_nm IS NOT NULL AND LTRIM(RTRIM(d.dealer_nm)) <> ''\n        AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n        AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\n        AND u.user_id NOT IN ('DM5103','DM9999','JB30007','JB30016','KMKS176','KMKS999','JB30067')\n)\nSELECT\n    CASE WHEN ISNULL(at2.tgt_cnt, 0) = 0 THEN 1.0\n         ELSE CAST(ISNULL(aa.ac_cnt, 0) AS float) / at2.tgt_cnt\n    END AS progress_pct\nFROM act_actual AS aa CROSS JOIN act_target AS at2`,
